  ('medical-tech-moex-20797', 'medical-tech', 'medical-tech-moex-093-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '自體溶血性疾病，輸血時之原則為何？ 有強度之溫型自體抗體者，對所有紅血球可能都有極強之反應，對於是否有異體抗體在檢驗上十分困 難，且無多大臨床上之好處，可以省去 冷型自體抗體，在37℃時沒反應者，可以預溫發血，加溫輸血即可 洗滌紅血球血品可以降低自體溶血程度，適合自體溶血病人 常見之溫型自體抗體，其抗原性以針對Kidd血型系最多見', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "33d4b0cf0707", "answer_pdf_sha1": "2b394db97a23", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 54, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
